interface Urun {
  isim: string;
  fiyat: number;
  miktar: number;
}

function urunFiltrele(urunler: Urun[], minFiyat: number, maxFiyat: number): Urun[] {
  return urunler.filter(function(urun) {
    return urun.fiyat >= minFiyat && urun.fiyat <= maxFiyat;
  });
}

let liste: Urun[] = [
  { isim: "Kalem", fiyat: 5, miktar: 100 },
  { isim: "Defter", fiyat: 15, miktar: 50 },
  { isim: "Silgi", fiyat: 3, miktar: 200 }
];
let sonuc = urunFiltrele(liste, 4, 10);
console.log(sonuc);

function kareDiziOlustur(sayilar: number[]): number[] {
  let kareler: number[] = [];
  for (let index = 0; index < sayilar.length; index++) {
    kareler.push(sayilar[index] * sayilar[index]);
  }
  return kareler;
}

let girdi: number[] = [1, 2, 3, 4, 5];
let cikti: number[] = kareDiziOlustur(girdi);
console.log(cikti);

interface Kullanici {
  isim: string;
  yas: number;
  sehir: string;
}

function yasKontrol(kullanici: Kullanici, sinir: number): string {
  if (kullanici.yas >= sinir) {
    return kullanici.isim + " gecerli";
  }
  return kullanici.isim + " gecersiz";
}

let kisi: Kullanici = { isim: "Ayse", yas: 22, sehir: "Ankara" };
let mesaj: string = yasKontrol(kisi, 18);
console.log(mesaj);

